.momentum-metric strong { font-size: 1.2rem; color: var(--accent-color, #2196F3); }
.momentum-metric small { color: var(--text-secondary, #888); }
.momentum-alert { padding: 8px 12px; border-radius: 8px; font-size: 0.8rem; width: 100%; box-sizing: border-box; }
.momentum-alert.flow { background: rgba(255,152,0,0.15); color: #ff9800; border: 1px solid rgba(255,152,0,0.3); }
.momentum-alert.low { background: rgba(244,67,54,0.12); color: #f44336; border: 1px solid rgba(244,67,54,0.25); }
.momentum-alert.high { background: rgba(76,175,80,0.12); color: #4caf50; border: 1px solid rgba(76,175,80,0.25); }
.momentum-summary-grid { display: flex; gap: 20px; font-size: 0.8rem; color: var(--text-secondary, #aaa); }
.momentum-summary-grid strong { color: var(--text-primary, #ddd); }

/* ── Smart Session Prioritizer ── */
#prioritizer-overlay{position:fixed;inset:0;background:rgba(0,0,0,.55);z-index:11000;display:none;justify-content:center;align-items:center}
#prioritizer-panel{display:none;flex-direction:column;width:540px;max-width:95vw;max-height:80vh;background:var(--bg-primary,#1e1e2e);border:1px solid var(--border-color,#333);border-radius:12px;box-shadow:0 8px 32px rgba(0,0,0,.45);color:var(--text-primary,#e0e0e0);overflow:hidden;z-index:11001}
.prioritizer-header{display:flex;justify-content:space-between;align-items:center;padding:14px 18px;border-bottom:1px solid var(--border-color,#333)}
.prioritizer-header h2{margin:0;font-size:1.1rem;font-weight:600}
.prioritizer-controls{display:flex;gap:8px;align-items:center}
.prioritizer-controls button,.prioritizer-controls select{background:var(--bg-secondary,#2a2a3c);color:var(--text-primary,#ccc);border:1px solid var(--border-color,#444);border-radius:6px;padding:4px 10px;cursor:pointer;font-size:.82rem}
.prioritizer-controls button:hover{background:var(--bg-hover,#3a3a50)}
.prioritizer-auto-label{font-size:.8rem;display:flex;align-items:center;gap:4px;cursor:pointer}
#prioritizer-list{overflow-y:auto;padding:10px 14px;flex:1}
.prioritizer-item{display:flex;align-items:center;gap:10px;padding:10px 12px;border-radius:8px;cursor:pointer;transition:background .15s}
.prioritizer-item:hover{background:var(--bg-hover,#2f2f45)}
.priority-badge{font-size:.85rem;font-weight:700;min-width:60px;text-align:center}
.priority-badge.critical{color:#ff5555}
.priority-badge.medium{color:#f0c040}
.priority-badge.low{color:#50e050}
.prioritizer-name{flex:1;font-size:.92rem;white-space:nowrap;overflow:hidden;text-overflow:ellipsis}
.prioritizer-tags{display:flex;flex-wrap:wrap;gap:4px}
.priority-tag{font-size:.7rem;padding:2px 7px;border-radius:10px;background:var(--bg-secondary,#2a2a3c);color:var(--text-secondary,#aaa)}
.prioritizer-empty{text-align:center;padding:32px;color:var(--text-secondary,#888);font-style:italic}

/* ============================================================
   Module: ConversationMemory
   ============================================================ */
.memory-panel{display:none;position:fixed;top:0;left:0;width:100%;height:100%;background:rgba(0,0,0,.55);z-index:10000}
.memory-panel-inner{position:absolute;top:4%;left:6%;width:88%;height:92%;background:var(--bg,#1a1a2e);border-radius:12px;display:flex;flex-direction:column;overflow:hidden;box-shadow:0 8px 32px rgba(0,0,0,.5)}
.memory-header{padding:12px 18px;display:flex;gap:10px;align-items:center;border-bottom:1px solid rgba(255,255,255,.08);flex-wrap:wrap}
.memory-header h3{margin:0;font-size:1.15rem;color:var(--fg,#eee);flex:1;white-space:nowrap}
.memory-search{flex:0 1 260px;padding:6px 10px;border-radius:8px;border:1px solid rgba(255,255,255,.12);background:var(--bg-secondary,#16213e);color:var(--fg,#eee);font-size:.85rem}
.memory-filters{display:flex;gap:6px;padding:8px 18px;border-bottom:1px solid rgba(255,255,255,.06);flex-wrap:wrap}
.memory-filter-btn{padding:4px 12px;border-radius:14px;border:1px solid rgba(255,255,255,.1);background:transparent;color:var(--text-secondary,#aaa);cursor:pointer;font-size:.78rem;transition:all .15s}
.memory-filter-btn.active,.memory-filter-btn:hover{background:var(--accent,#2196f3);color:#fff;border-color:var(--accent,#2196f3)}
.memory-stats{display:flex;gap:14px;padding:8px 18px;font-size:.78rem;color:var(--text-secondary,#999);border-bottom:1px solid rgba(255,255,255,.04);flex-wrap:wrap}
.memory-stat-chip{display:inline-flex;align-items:center;gap:4px}
.memory-list{flex:1;overflow-y:auto;padding:12px 18px}
.memory-card{background:var(--bg-secondary,#16213e);border-radius:10px;padding:12px 14px;margin-bottom:10px;display:flex;flex-direction:column;gap:6px;border-left:3px solid transparent}
.memory-card[data-type="fact"]{border-left-color:#42a5f5}
.memory-card[data-type="decision"]{border-left-color:#66bb6a}
.memory-card[data-type="preference"]{border-left-color:#ab47bc}
.memory-card[data-type="action"]{border-left-color:#ffa726}
.memory-card[data-type="insight"]{border-left-color:#26a69a}
.memory-card-top{display:flex;align-items:center;gap:8px}
.memory-type-badge{font-size:.7rem;padding:2px 8px;border-radius:10px;color:#fff;font-weight:600;text-transform:uppercase}
.memory-type-badge.fact{background:#42a5f5}
.memory-type-badge.decision{background:#66bb6a}
.memory-type-badge.preference{background:#ab47bc}
.memory-type-badge.action{background:#ffa726}
.memory-type-badge.insight{background:#26a69a}
.memory-card-content{font-size:.88rem;color:var(--fg,#ddd);line-height:1.45}
.memory-card-meta{font-size:.72rem;color:var(--text-secondary,#777);display:flex;justify-content:space-between;align-items:center}
.memory-card-del{background:none;border:none;color:var(--text-secondary,#777);cursor:pointer;font-size:.75rem;padding:2px 6px;border-radius:4px}
.memory-card-del:hover{color:#e57373;background:rgba(229,115,115,.12)}
.memory-indicator{position:fixed;bottom:72px;right:24px;background:var(--accent,#2196f3);color:#fff;border:none;border-radius:20px;padding:4px 12px;font-size:.8rem;cursor:pointer;z-index:9000;box-shadow:0 2px 8px rgba(0,0,0,.3);display:none;animation:memPulse 2s infinite}
@keyframes memPulse{0%,100%{opacity:1}50%{opacity:.7}}
.memory-recall-popup{position:fixed;bottom:110px;right:24px;width:340px;max-height:260px;overflow-y:auto;background:var(--bg,#1a1a2e);border:1px solid rgba(255,255,255,.1);border-radius:10px;box-shadow:0 4px 20px rgba(0,0,0,.4);z-index:9001;padding:10px;display:none}
.memory-recall-item{padding:6px 8px;border-radius:6px;margin-bottom:4px;font-size:.8rem;color:var(--fg,#ddd);background:var(--bg-secondary,#16213e);cursor:pointer}
.memory-recall-item:hover{background:rgba(33,150,243,.15)}
.memory-empty{text-align:center;padding:40px;color:var(--text-secondary,#888);font-style:italic}

/* ---- Conversation Coach ---- */
.coach-tip-bar{display:flex;align-items:center;gap:8px;padding:6px 12px;margin:4px 0;background:rgba(59,130,246,.1);border:1px solid rgba(59,130,246,.25);border-radius:8px;font-size:13px;color:var(--text-color,#e0e0e0);animation:coachFadeIn .3s ease}
.coach-tip-icon{font-size:16px}
.coach-tip-text{flex:1}
.coach-tip-close{background:none;border:none;color:var(--text-color,#e0e0e0);font-size:16px;cursor:pointer;padding:0 4px;opacity:.6}
.coach-tip-close:hover{opacity:1}
@keyframes coachFadeIn{from{opacity:0;transform:translateY(4px)}to{opacity:1;transform:translateY(0)}}

.coach-dashboard-overlay{display:none;position:fixed;inset:0;z-index:10000;background:rgba(0,0,0,.5);align-items:center;justify-content:center}
.coach-dashboard-content{background:var(--bg-color,#1e1e2e);color:var(--text-color,#e0e0e0);border-radius:12px;padding:24px;max-width:420px;width:90%;box-shadow:0 8px 32px rgba(0,0,0,.4)}
.coach-dash-header{display:flex;justify-content:space-between;align-items:center;margin-bottom:16px}
.coach-dash-header h3{margin:0;font-size:18px}
.coach-dash-close{background:none;border:none;color:var(--text-color,#e0e0e0);font-size:20px;cursor:pointer}
.coach-dash-score{text-align:center;margin:16px 0}
.coach-score-circle{width:80px;height:80px;border-radius:50%;background:conic-gradient(#3b82f6 calc(var(--score)*3.6deg),rgba(255,255,255,.1) 0);display:inline-flex;align-items:center;justify-content:center;position:relative}
.coach-score-circle::before{content:'';position:absolute;inset:8px;border-radius:50%;background:var(--bg-color,#1e1e2e)}
.coach-score-circle span{position:relative;font-size:24px;font-weight:700}
.coach-score-label{margin-top:8px;font-size:13px;opacity:.7}
.coach-dash-stats{display:grid;grid-template-columns:1fr 1fr;gap:12px;margin:16px 0}
.coach-stat{text-align:center;padding:8px;background:rgba(255,255,255,.05);border-radius:8px}
.coach-stat-val{display:block;font-size:18px;font-weight:600}
.coach-stat-lbl{font-size:11px;opacity:.6}
.coach-dash-tips{margin:16px 0}
.coach-dash-tips h4{margin:0 0 8px;font-size:14px}
.coach-dash-tips ul{margin:0;padding-left:20px;font-size:13px}
.coach-dash-tips li{margin:4px 0}
.coach-toggle-label{font-size:13px;display:flex;align-items:center;gap:8px;cursor:pointer;opacity:.8}
